render.css:
.logs-container { background: var(--ct-bg-deep); border: 1px solid var(--ct-surface-2); border-radius: 4px; padding: 8px; height: 180px; overflow: hidden; font-family: ui-monospace, monospace; font-size: 11px; color: var(--ct-text-muted); }
.logs-stream { animation: logScroll 30s linear infinite; }
.log-line { padding: 2px 0; white-space: nowrap; }
.log-highlight { color: var(--ct-text-strong); font-weight: 600; }
.cursor-blink { display: inline-block; width: 6px; height: 10px; background: var(--ct-text-strong); animation: blink 1s steps(1) infinite; vertical-align: middle; }
@keyframes blink { 0%, 50% { opacity: 1; } 51%, 100% { opacity: 0; } }
@keyframes logScroll { from { transform: translateY(0); } to { transform: translateY(-50%); } }
